    "business_context": "The system already has an established domain concept of 'confirmed' in the Orders bounded context, meaning 'paid and queued for fulfillment, immutable.' A new feature request proposes reusing the term 'confirmed' in the Quotes bounded context with a fundamentally different meaning: 'verbally agreed but unpaid.' This is a direct collision in the ubiquitous language.",
    "bounded_context": "Cross-context: Orders (established) and Quotes (proposed change)",
    "ubiquitous_language": [
      { "term": "Confirmed Order", "definition": "An order that has been paid and is queued for fulfillment. It is immutable — no fields may be changed after confirmation." },
      { "term": "Confirmed Quote (PROPOSED)", "definition": "A quote where the customer has verbally agreed to terms, but payment has NOT occurred. This is a pre-payment state and is NOT immutable." },
      { "term": "Quote", "definition": "A proposed set of terms and pricing offered to a customer, subject to acceptance." },
      { "term": "Immutable", "definition": "Cannot be modified after entering this state. A hard invariant in the Orders context." }
    ]
  },

  "business_rules": [],

  "acceptance_criteria": [],

  "edge_cases": [
    { "scenario": "A developer sees 'confirmed' in code and assumes it means paid and immutable, as established by the Orders context. They skip payment validation on a confirmed quote.", "expected_behavior": "This must never happen. The two meanings of 'confirmed' create a trap for anyone working across both contexts." },
    { "scenario": "A report shows 'confirmed' items across both orders and quotes. A finance team member interprets all 'confirmed' records as revenue-committed.", "expected_behavior": "Confirmed quotes are NOT revenue-committed — they are verbal agreements with no payment. Conflating them with confirmed orders would overstate revenue pipeline." },
    { "scenario": "An integration or event bus emits a 'Confirmed' event. Downstream consumers cannot distinguish between a confirmed order (paid, immutable) and a confirmed quote (verbal agreement, mutable, unpaid).", "expected_behavior": "Event consumers must never confuse the two. A shared term across contexts makes this error likely." }
  ],

  "business_impact": {
    "financial": "HIGH RISK. If 'confirmed quote' is conflated with 'confirmed order' in reporting, revenue recognition, or downstream automation, the business could misstate revenue pipeline or prematurely trigger fulfillment for unpaid work.",
    "operational": "Developers, QA, support staff, and analysts will face ongoing cognitive overhead distinguishing two meanings of the same term. This is a permanent source of bugs and miscommunication.",
    "user": "Sales agents need a status reflecting verbal agreement — that business need is legitimate. But the term chosen to represent it is dangerous.",
    "risk": "Domain language corruption. Once the ubiquitous language fractures — where the same word means different things in different contexts — every future conversation, ticket, report, and integration becomes ambiguous. This is one of the most expensive forms of technical and organizational debt.",
    "stakeholders_affected": [
      { "group": "Engineering", "impact": "Permanent ambiguity in domain model. Every developer touching orders or quotes must mentally disambiguate 'confirmed.' Bug surface area increases." },
      { "group": "Finance / Revenue Ops", "impact": "Risk of overstating committed revenue if confirmed quotes are mistaken for confirmed (paid) orders in dashboards or reports." },
      { "group": "Sales Agents", "impact": "Legitimate need for a 'customer verbally agreed' status. The need is valid; the naming is not." },
      { "group": "Support / Operations", "impact": "When a customer calls about a 'confirmed' item, support cannot know if it's paid-and-immutable or verbal-and-unpaid without checking which entity type it is." },
      { "group": "Integration Partners", "impact": "Any system consuming events or API payloads with a 'confirmed' status will face ambiguity across entity types." }
    ]
  },

  "confidence": {
    "level": 95,
    "reasoning": "The existing domain definition is explicit and unambiguous. The proposed feature request directly contradicts the established meaning of 'confirmed' on three axes: payment status (paid vs unpaid), mutability (immutable vs mutable), and commitment level (contractual vs verbal). This is not a gray area — it is a clear ubiquitous language violation.",
    "high_confidence_areas": [
      "The term 'confirmed' is already claimed with a precise, established meaning",
      "The proposed meaning differs on payment, mutability, and commitment level",
      "This will cause cross-context confusion in code, reporting, and communication"
    ],
    "low_confidence_areas": [
      "The exact alternative term the business would prefer (requires stakeholder input)"
    ],
    "assumptions": [
      "The existing definition of 'confirmed order' is authoritative and in active use",
      "Orders and Quotes are separate bounded contexts but share organizational vocabulary"
    ]
  },

  "escalations": [
    {
      "type": "contradiction",
      "description": "The term 'confirmed' is being assigned two mutually exclusive meanings. In Orders: paid, immutable, queued for fulfillment. In Quotes (proposed): unpaid, mutable, verbal agreement only. Same word, opposite semantics on every dimension that matters. This violates the principle of ubiquitous language — a term must mean ONE thing across the domain, or be explicitly scoped with a qualifier that prevents confusion.",
      "affected_stakeholders": ["Engineering", "Finance", "Sales", "Support", "Integration Partners"],
      "options": [
        "REJECT the term 'confirmed' for quotes. Use a distinct term that accurately reflects the business state, such as 'Verbally Accepted', 'Customer Agreed', or 'Pending Payment'.",
        "RENAME the existing order status to something more specific (e.g., 'Payment Confirmed') and allow 'confirmed' to be used for quotes — but this is far more disruptive and risks breaking existing integrations.",
        "ALLOW the overload but enforce strict qualification everywhere ('quote-confirmed' vs 'order-confirmed') — this is a band-aid that will erode over time."
      ],
      "recommendation": "Option 1: Reject 'confirmed' for quotes. The sales team's need is real — they need a status for 'customer verbally agreed, awaiting payment.' But that status should be named for what it IS, not overloaded onto a term that already means something fundamentally different. Suggested alternatives: 'Accepted' (quote accepted by customer), 'Agreed' (terms agreed), or 'Pending Payment' (explicit about what's missing). The cheapest fix is always at the language level, before a single line of code is written."
    }
  ],

  "rejection_reasons": [
    { "violation": "Ubiquitous language collision: 'confirmed' already means 'paid, immutable, queued for fulfillment' in the Orders context. Reusing it for 'unpaid, mutable, verbal agreement' in Quotes corrupts the shared domain language.", "business_rule_broken": "A confirmed order is paid and immutable. A 'confirmed quote' as proposed is neither. The same term cannot encode opposite business states." }
  ]
